nta.declaration:
//  global declarations .


// This research has been carried out in IRT SystemX, Paris-Saclay, France, and therefore granted with public funds of the French Program “Investissements d’Avenir”.
// This code is published under license MIT : https://spdx.org/licenses/MIT.html

const int NU = -1; 

const int nbVar =5;
const int dnbVar = (nbVar>0)? nbVar : 1;
const int NbStates = 4; // 0 == F, 1 == M, 2 == B, 3 == N

const int sF=0; const int sM=1; const int sB=2; const int sT=2; const int sN=3;//node states, F:functional, M:malware, B/T: bad==tainted data, N: non available, do nor change values !!!!!
const int mand=1; const int opt=0; const int transp=NU;
// old denomination const int pF=0; const int pP=1; const int pA=2; //attacker position
const int peer=0; const int mitm=1; const int side=2; //attacker position, new format
const int cU=0; const int cR=1; const int cK=2; // knode type , User space, Root, Kernel Space
const int user=0; const int root=1; const int kernel=2;
const int rA=0, rS=1; // application , system role
const int MaxUnitCost=100; // max unitary cost
//const int MaxInputWeight=10; // abandonned, too complex  
//const int MaxInputWeights=MaxInputWeight*10; // abandonned, too complex  
const int MaxRoles=10; // new max roles per components


broadcast chan startCh; // start sychro

broadcast chan reset; // used to reset nodes after an anomaly detection



const int nbNodes = 15; // component number


typedef struct {
    int[0,NbStates-1] locat; // 0 == F, 1 == M, 2 == B, 3 == N
} nodeState_t;  // node state, init all = F == 1


// Secrets originally stored

const bool StoredSecrets [nbNodes] [dnbVar]={
//	0:IntraCustomerSecret 1:ExternCustomerSecret 2:Iot1Secret 3:Iot2Secret 4:DmzHttpSecret 

	{false,false,false,false,true},	//DmzHttp
	{false,false,false,false,false},	//DmzLinx
	{false,true,false,false,false},	//ExBrowser
	{false,false,false,false,false},	//ExtHack
	{false,false,false,false,false},	//ExtWind
	{false,false,false,false,false},	//FW
	{true,false,false,false,false},	//InBrowser
	{false,false,false,false,false},	//IntHack
	{false,false,false,false,false},	//IntWind
	{false,false,false,false,false},	//Internet
	{false,false,false,false,false},	//Intranet
	{false,false,false,false,false},	//IoTLinx1
	{false,false,false,false,false},	//IoTLinx2
	{false,false,true,false,false},	//IoTSrv1
	{false,false,false,true,false}	//IoTSrv2
};

const int NodesKernels [nbNodes] ={
1,-1,4,-1,-1,-1,8,-1,-1,-1,-1,-1,-1,11,12
};


// Stolen Secrets 
bool StolenSecrets[dnbVar]={false,false,false,false,false};



nodeState_t nodeState[nbNodes]={ 
{	sF } /* node: 0:DmzHttp */,
{	sF } /* node: 1:DmzLinx */,
{	sF } /* node: 2:ExBrowser */,
{	sM } /* node: 3:ExtHack */,
{	sF } /* node: 4:ExtWind */,
{	sF } /* node: 5:FW */,
{	sF } /* node: 6:InBrowser */,
{	sF } /* node: 7:IntHack */,
{	sF } /* node: 8:IntWind */,
{	sF } /* node: 9:Internet */,
{	sF } /* node: 10:Intranet */,
{	sF } /* node: 11:IoTLinx1 */,
{	sF } /* node: 12:IoTLinx2 */,
{	sF } /* node: 13:IoTSrv1 */,
{	sF } /* node: 14:IoTSrv2 */
};

const int maxCosts=65;
int[-1,MaxUnitCost*20] costs=0;
const int maxSteps=6;
int [0,maxSteps] stepNb=0;


const int fallBackMode[nbNodes][3]= { // fallback number for sM, sB or sN locals
{0,0,0} /* node: 0:DmzHttp */,
{NU,NU,NU} /* node: 1:DmzLinx */,
{NU,NU,NU} /* node: 2:ExBrowser */,
{NU,NU,NU} /* node: 3:ExtHack */,
{NU,NU,NU} /* node: 4:ExtWind */,
{NU,NU,NU} /* node: 5:FW */,
{NU,NU,NU} /* node: 6:InBrowser */,
{NU,NU,NU} /* node: 7:IntHack */,
{NU,NU,NU} /* node: 8:IntWind */,
{NU,NU,NU} /* node: 9:Internet */,
{NU,NU,NU} /* node: 10:Intranet */,
{NU,NU,NU} /* node: 11:IoTLinx1 */,
{NU,NU,NU} /* node: 12:IoTLinx2 */,
{NU,NU,NU} /* node: 13:IoTSrv1 */,
{NU,NU,NU} /* node: 14:IoTSrv2 */
};

void FallBack(int node_id, int[0,NbStates-1] locat) {

int mode=fallBackMode[node_id][locat-1];

if (mode==NU) return;
	if (mode==0) { // ResetInfra
		nodeState[5].locat=sF;nodeState[1].locat=sF;nodeState[0].locat=sF;StolenSecrets[0]=false;StolenSecrets[4]=false; return;
	}

    return;
}

template.declaration:
// Place local declarations here.

// This research has been carried out in IRT SystemX, Paris-Saclay, France, and therefore granted with public funds of the French Program “Investissements d’Avenir”.
// This code is published under license MIT : https://spdx.org/licenses/MIT.html

	const int NbInputs = 41; // per node
	const int diM = (NbInputs>0)? NbInputs : 1;
    const int NbRoles = 5;
    const int kernelIndex = 1;
    const int diMr = (NbRoles>0)? NbRoles : 1;

    typedef struct {
        int[NU,nbNodes-1] node_id; // input node id,  -1/NU not used
        int[NU,2] attack_position; // peer 0 , mitm 1 == ,side 2 
        int [0,diMr] roleId; // role id of attacked component, local id
        bool tunnelOn; // true if tunnel on
        int protCost[4];  // attack on protocols:  "0" session entrance cost (0 for peer), "1" break (down), tunnel compromission costs ("2" tunnel entrance, "3" tunnel break) , already adapted to the attacker position, NU for costs == impossible to break  
    } input_t; // input description, for each interaction


	typedef struct {
	    int[0,nbNodes-1] node_id;
 	    int[0, 2] node_type; // 0 == user space component , 1 == root space component, 2 == kernel
        int plausThreshold,actThreshold; // min of Bd roles to be bad data, min of active rA roles != 'mandatory' to be sF or sB , mandatory roles no included
	    int[NU,MaxUnitCost] secrTheftCost; // steal all the secrets stored locally, by already installed local malware 
        int AnomDetParam[3];  // 3 costs for bypassing anomaly detection : m, b, n, if <0, monitoring disabled
        int RoleParams[diMr][7]; // role params, 7 values :  
                                    // 0 role type: rA==app rS==system, 
                                    // 1 importance (!= NU only for rA) Nu=='transparent' 0=='optional' 1=='mandatory',  
                                    // 2 bad data acceptability cost, 
                                    // 3,4,5 malware install costs :malware ,bad data only ,non available only,
                                    // 6 cost of theft of locally stored secrets by remote malware
	    input_t in[diM]; 
	} node_t; // node description, for topology

const int roleProtectKey[diMr][dnbVar]={
	{true,true,false,false,false},
	{false,false,true,false,false},
	{false,false,false,true,false},
	{false,false,false,false,false},
	{false,false,false,false,false}
};

	const node_t node =
	{0,user,2,1,10,{NU,NU,NU},
		{//Roles
			{rA,transp,5,25,20,15,20},
			{rA,opt,5,25,20,15,20},
			{rA,opt,5,25,20,15,20},
			{rS,mand,NU,20,10,1,10},
			{rS,mand,NU,10,10,1,10}
		},
		{//Inputs
			{1,mitm,1,false,{25,0,NU,NU}}	/* DmzLinx	*/,
			{5,mitm,1,false,{25,0,NU,NU}}	/* FW	*/,
			{7,side,1,false,{25,20,NU,NU}}	/* IntHack	*/,
			{8,side,1,false,{25,20,NU,NU}}	/* IntWind	*/,
			{10,mitm,1,false,{25,0,NU,NU}}	/* Intranet	*/,
			{11,mitm,1,false,{25,0,NU,NU}}	/* IoTLinx1	*/,
			{12,side,1,false,{25,20,NU,NU}}	/* IoTLinx2	*/,
			{13,peer,1,false,{25,0,NU,NU}}	/* IoTSrv1	*/,
			{1,mitm,2,false,{25,0,NU,NU}}	/* DmzLinx	*/,
			{5,mitm,2,false,{25,0,NU,NU}}	/* FW	*/,
			{7,side,2,false,{25,20,NU,NU}}	/* IntHack	*/,
			{8,side,2,false,{25,20,NU,NU}}	/* IntWind	*/,
			{10,mitm,2,false,{25,0,NU,NU}}	/* Intranet	*/,
			{11,side,2,false,{25,20,NU,NU}}	/* IoTLinx1	*/,
			{12,mitm,2,false,{25,0,NU,NU}}	/* IoTLinx2	*/,
			{14,peer,2,false,{25,0,NU,NU}}	/* IoTSrv2	*/,
			{1,mitm,0,false,{25,0,NU,NU}}	/* DmzLinx	*/,
			{1,mitm,0,false,{25,0,NU,NU}}	/* DmzLinx	*/,
			{2,side,0,false,{25,20,NU,NU}}	/* ExBrowser	*/,
			{2,peer,0,false,{25,0,NU,NU}}	/* ExBrowser	*/,
			{3,side,0,false,{25,20,NU,NU}}	/* ExtHack	*/,
			{3,side,0,false,{25,20,NU,NU}}	/* ExtHack	*/,
			{4,side,0,false,{25,20,NU,NU}}	/* ExtWind	*/,
			{4,mitm,0,false,{25,0,NU,NU}}	/* ExtWind	*/,
			{5,mitm,0,false,{25,0,NU,NU}}	/* FW	*/,
			{5,mitm,0,false,{25,0,NU,NU}}	/* FW	*/,
			{6,peer,0,false,{25,0,NU,NU}}	/* InBrowser	*/,
			{6,side,0,false,{25,20,NU,NU}}	/* InBrowser	*/,
			{7,side,0,false,{25,20,NU,NU}}	/* IntHack	*/,
			{7,side,0,false,{25,20,NU,NU}}	/* IntHack	*/,
			{8,mitm,0,false,{25,0,NU,NU}}	/* IntWind	*/,
			{8,side,0,false,{25,20,NU,NU}}	/* IntWind	*/,
			{9,side,0,false,{25,20,NU,NU}}	/* Internet	*/,
			{9,mitm,0,false,{25,0,NU,NU}}	/* Internet	*/,
			{10,mitm,0,false,{25,0,NU,NU}}	/* Intranet	*/,
			{10,side,0,false,{25,20,NU,NU}}	/* Intranet	*/,
			{11,side,0,false,{25,20,NU,NU}}	/* IoTLinx1	*/,
			{11,side,0,false,{25,20,NU,NU}}	/* IoTLinx1	*/,
			{12,side,0,false,{25,20,NU,NU}}	/* IoTLinx2	*/,
			{12,side,0,false,{25,20,NU,NU}}	/* IoTLinx2	*/,
			{1,peer,4,false,{0,NU,NU,NU}}	/* DmzLinx	*/
		}
	};




     bool isFallBackActiv(int[0,nbNodes-1] NodeIndex,int[0,NbStates-1] Targetlocation) {
        return (node.AnomDetParam[Targetlocation-1] != NU) and ( fallBackMode[node.node_id][Targetlocation-1] !=NU);
    }


    bool key(int[0,nbNodes-1] sourceNodeIndex,int[0,nbVar-1] secrId) {
        int idKernel=NodesKernels[sourceNodeIndex];
        bool ret=StolenSecrets[secrId] or StoredSecrets[sourceNodeIndex][secrId];
        if (idKernel>0) ret=ret or StoredSecrets[idKernel][secrId];
        return ret;
    }


    int ProtProtectCost(int[0,diM-1] inpId, int roleId, int[0,nbNodes-1] sourceNodeIndex,int[NU,2] attack_position,int[0,NbStates-1] attackerState) { // cost of protocol session theft
        int protCost=node.in[inpId].protCost[0],tunCost=node.in[inpId].protCost[2]; bool keyProtect=false;
        int kernelSId=NodesKernels[sourceNodeIndex];

        if (attackerState==sF) return NU;
        if (attackerState==sN) return NU;
        if (attackerState!=sM and attack_position!=peer) return NU;


        for (i : int[0,nbVar-1] ) {
            if (roleProtectKey[roleId][i]) {
                bool kerSt=false;if (kernelSId !=NU) kerSt=StoredSecrets[kernelSId][i];
                keyProtect=true;if (StolenSecrets[i] or StoredSecrets[sourceNodeIndex][i] or kerSt) protCost=0;
            } // application protocol is set to zero if one of the protection secret is available
        }
        if (attack_position==peer) {if (keyProtect) return protCost;else return 0;} // special case for PF position, only application protocol is to consider
        if (node.in[inpId].tunnelOn) { if (protCost==NU or tunCost==NU) return NU; else return (protCost+tunCost); } else return protCost;
    }


    int ProtDestructCost(int[0,diM-1] inpId, int roleId, int[0,nbNodes-1] sourceNodeIndex,int[NU,2] attack_position,int[0,NbStates-1] attackerState) { // cost of protocol session theft
        int protCostBr=node.in[inpId].protCost[1],tunCostBr=node.in[inpId].protCost[3]; bool keyProtect=false;
        int protCost=node.in[inpId].protCost[0],tunCost=node.in[inpId].protCost[2];
        int kernelSId=NodesKernels[sourceNodeIndex];

        if (attackerState==sF) return NU;
        if (attackerState==sN and attack_position==peer) return 0;
        if (attackerState!=sM and attack_position!=peer) return NU;


        if (protCostBr==NU or (protCost!=NU and protCost<protCostBr)) protCostBr=protCost; // normally it si easier to put down than enter, but we consider also the contray case
        for (i : int[0,nbVar-1] ) {
            if (roleProtectKey[roleId][i]) {
                bool kerSt=false;if (kernelSId !=NU) kerSt=StoredSecrets[kernelSId][i];
                keyProtect=true;if (StolenSecrets[i] or StoredSecrets[sourceNodeIndex][i] or kerSt) protCostBr=0;
            } // application protocol is set to zero if one of the protection secret is available
        }

        if (attack_position==peer) {if (keyProtect) return protCostBr;else return 0;} // special case for PF position, only application protocol is to consider if key is available

        if (node.in[inpId].tunnelOn) {
            if (tunCost==NU or protCostBr==NU or ( (tunCost+protCost) > tunCostBr ) ) return tunCostBr; // impossible to enter tunnel 
            return (protCostBr+tunCostBr);
        } else return protCostBr; // no tunel only application prooc is to consider
    }



	bool reachable (int[0,diM-1] inp) { // true if this node can be visible by the input_node
	if (inp ==0) return ( nodeState[1].locat != sN);
	if (inp ==1) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN);
	if (inp ==2) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[7].locat != sN);
	if (inp ==3) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[8].locat != sN);
	if (inp ==4) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN);
	if (inp ==5) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[11].locat != sN);
	if (inp ==6) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[12].locat != sN);
	if (inp ==7) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[11].locat != sN);
	if (inp ==8) return ( nodeState[1].locat != sN);
	if (inp ==9) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN);
	if (inp ==10) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[7].locat != sN);
	if (inp ==11) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[8].locat != sN);
	if (inp ==12) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN);
	if (inp ==13) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[11].locat != sN);
	if (inp ==14) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[12].locat != sN);
	if (inp ==15) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[12].locat != sN);
	if (inp ==16) return ( nodeState[1].locat != sN);
	if (inp ==17) return ( nodeState[1].locat != sN);
	if (inp ==18) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[9].locat != sN and  nodeState[4].locat != sN);
	if (inp ==19) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[9].locat != sN and  nodeState[4].locat != sN);
	if (inp ==20) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[9].locat != sN and  nodeState[3].locat != sN);
	if (inp ==21) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[9].locat != sN and  nodeState[3].locat != sN);
	if (inp ==22) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[9].locat != sN and  nodeState[4].locat != sN);
	if (inp ==23) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[9].locat != sN and  nodeState[4].locat != sN);
	if (inp ==24) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN);
	if (inp ==25) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN);
	if (inp ==26) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[8].locat != sN);
	if (inp ==27) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[8].locat != sN);
	if (inp ==28) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[7].locat != sN);
	if (inp ==29) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[7].locat != sN);
	if (inp ==30) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[8].locat != sN);
	if (inp ==31) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[8].locat != sN);
	if (inp ==32) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[9].locat != sN);
	if (inp ==33) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[9].locat != sN);
	if (inp ==34) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN);
	if (inp ==35) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN);
	if (inp ==36) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[11].locat != sN);
	if (inp ==37) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[11].locat != sN);
	if (inp ==38) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[12].locat != sN);
	if (inp ==39) return ( nodeState[1].locat != sN and  nodeState[5].locat != sN and  nodeState[10].locat != sN and  nodeState[12].locat != sN);
	if (inp ==40) return ( nodeState[1].locat != sN);
	    return false;
	} 


    int minBadDataCost() { // returns the sum of costs for all inputs capable of producing bad data, Nu if impossible 
        int[NU,MaxUnitCost] rolCostBd[diMr] = {NU,NU,NU,NU,NU};
        bool rolOk[diMr] = {false,false,false,false,false};  // true if a role can stay OK thanks to legitimate producers

        int bdCost=0, tcost=NU, tr=0,totRolOK=0,totRolBd=0, mustcopromise=NU, nbCompr=0,activityCost=0; // tcost total min cost        
        int tr1=NU, j=NU;
	    if (NbInputs <=0) return NU;if (node.node_type==cK) return NU;
        for(i : int[0,diMr-1] ) rolOk[i]=true;
        for(i : int[0,diM-1] ) rolOk[node.in[i].roleId]=false;

       // for all no system inputs: we memorise potentiel B et M available attacker nodes and costs of B data submissions, B cost in composed from two values, session breaking and acceptable bad data generation, sum of Ok Weight 
       // first round, minimal costs  for available partners 
	 	for(i : int[0,diM-1] ) if ( reachable(i) and (node.RoleParams[node.in[i].roleId][0]!=rS) and (node.RoleParams[node.in[i].roleId][1]!=transp)) { // available inputs,  no system and important roles only
           int[0,NbStates-1] attackerState=nodeState[node.in[i].node_id].locat;
           int[0,diMr-1] role = node.in[i].roleId; 
           int[NU,2] attack_position=node.in[i].attack_position;
           int costDir=node.RoleParams[role][2], protCost=ProtProtectCost(i,role,node.in[i].node_id,attack_position,attackerState), tt=NU; // costDir : cost of creation of acceptable data by role, protCost : cost of protocol break
           if ((protCost==NU) or (costDir==NU)) tt=NU; else tt=costDir+protCost;
           if ( (tt!=NU) and ( (attackerState==sM) or ( (attackerState==sB) and (attack_position==peer) ) ) ) if (rolCostBd[role]==NU or rolCostBd[role]>tt) rolCostBd[role]=tt; // looking for the minimal cost of roles !!!!!!!!!!!!!!!!
           if ( (attackerState==sF) and (attack_position==peer) ) rolOk[role]=true;
	 	}
        // number of roles OK and potentially compromisable, compliance with mandatory roles
        for(role : int[0,diMr-1] ) if (node.RoleParams[role][0]!=rS) { //no system roles
            if ( node.RoleParams[role][1]==mand) {  // mandatory role
                if ( (rolCostBd[role]<=NU) and not rolOk[role] ) return NU; // impossible to compromise not active mandatory role
                if (not rolOk[role] ) mustcopromise = (mustcopromise>NU)?mustcopromise+rolCostBd[role]:rolCostBd[role]; // cost of compromission of all manadatrory and not OK roles
                if ( (tcost==NU) or (rolCostBd[role]<tcost) ) tcost=rolCostBd[role]; // minimal cost of  the compromissions of one of the mandatory role => tcost 
            } else if ( (node.RoleParams[role][1]==0) and rolOk[role] ) totRolOK++; //number of OK optionnal roles
        }

        //if ( (totRolBmf + totRolOK) < node.actThreshold ) return NU; // no enough of OK or possible to compromise  optional roles, i.e. not enough of possible active roles
        if ( (mustcopromise>NU) and (totRolOK >=node.actThreshold) ) return mustcopromise;

      // adding necessary non active optional roles for minimal activity
        nbCompr =node.actThreshold - totRolOK;
        activityCost=0;totRolBd=0;
        for(k : int[0,diMr-1] ) if (nbCompr>0){
          tr1=NU;
          for(role : int[0,diMr-1] ) if ( (node.RoleParams[role][0]!=rS) and (node.RoleParams[role][1]==opt) and (rolCostBd[role] > NU) and not rolOk[role] )  { //only optional, no system roles
            if ( (tr1==NU) or (tr1>rolCostBd[role]) )  { tr1=rolCostBd[role]; j=role; } // role of min cost
          }
          if ( tr1!=NU ) { nbCompr--; totRolBd++; activityCost += tr1; rolCostBd[j]=NU; totRolOK++;}
        }   
        if (nbCompr>0) return NU; // impossible to have enough active optional roles

       if (mustcopromise>NU) return activityCost + mustcopromise; // no necessary to add supplementary optionnal role to achieve plausThreshold

       // adding necessary active optional roles for input bad data
        nbCompr =node.plausThreshold - totRolBd; // totRolBd === already compromised optional roles to maintain activity
        bdCost=NU;
        for(k : int[0,diMr-1] ) if (nbCompr>0){ // for OK role only
          tr1=NU;
          for(role : int[0,diMr-1] ) if ( (node.RoleParams[role][0]!=rS) and (node.RoleParams[role][1]==opt) and (rolCostBd[role] > NU) and rolOk[role] )  { //only optional roles
            if ( (tr1==NU) or (tr1>rolCostBd[role]) )  { tr1=rolCostBd[role]; j=role; } // role of min cost
          }
          if ( tr1!=NU ) { nbCompr--; if (bdCost!=NU) bdCost += tr1; else bdCost = tr1; rolCostBd[j]=NU; }
        }   

        if ( (nbCompr>0) and (tcost<0) ) return NU; // not enough of bad data and impossible to compromise manadatory roles  
        if (tcost<0) {
            if (bdCost<0) return activityCost;
            return activityCost + bdCost;
        }
        if (bdCost!=NU) return activityCost+(tcost<bdCost)?tcost:bdCost;
        return activityCost+tcost;       
    }

    int BadData(int[NU,nbNodes-1] node_id, bool fallback) { // fallback == true if possible fallback will be thrown
        int badDataCost, suppl=0;
        if (fallback and not isFallBackActiv(node_id,sB) ) return NU;
        if ( (not fallback) and isFallBackActiv(node_id,sB) ) suppl=node.AnomDetParam[sB-1];
        badDataCost=minBadDataCost();
        if (badDataCost == NU) return NU;
        badDataCost+=suppl;
        if ( (badDataCost+costs)<= maxCosts ) return badDataCost;
        return NU;
    }

    void updateBadData(int[NU,nbNodes-1] node_id, bool fallback) {
        int badDataCost=minBadDataCost(), suppl=0;
        if ( (not fallback) and  isFallBackActiv(node_id,sB) ) suppl=node.AnomDetParam[sB-1];
        costs += badDataCost+suppl;
        if (not fallback) nodeState[node_id].locat=sB;
    }


    int minNonDispCost() { // returns the sum of costs for all inputs able to produce Non availability state (sN), Nu if impossible 
        int[NU,MaxUnitCost] rolCostBdM[diMr] = {NU,NU,NU,NU,NU}; // 
        bool rolOk[diMr] = {false,false,false,false,false};  // true if a role can stay OK thanks to legitimate producers, "no system roles only" are considered
        int nbOKnMand=0, tcost=NU, nbtocomp=0;// tcost total min cost 
        int bdCost=NU,tr=NU;


        // "N" malware installation is considered in the  MinCostMalware function    

	    if (NbInputs <=0) return NU;

        for(i : int[0,diMr-1] ) rolOk[i]=true;
        for(i : int[0,diM-1] ) rolOk[node.in[i].roleId]=false;



        // for all "no system" inputs: we memorise potentiel B et M available attacker nodes and costs of non acceptable data submissions or (for M only) session destruction, this cost 0 for peer position and session breaking for others


	 	for(i : int[0,diM-1] ) if ( reachable(i) and (node.RoleParams[node.in[i].roleId][1]!=NU) and (node.RoleParams[node.in[i].roleId][0]!=rS) ) { // reachable  and important  
           int[0,NbStates-1] attackerState=nodeState[node.in[i].node_id].locat;
           int[0,diMr-1] role = node.in[i].roleId; 
           int[NU,2] attack_position=node.in[i].attack_position;
           int sessDestruct=NU;

           if ( (attackerState==sF) and (attack_position==peer) ) rolOk[role]=true;

           if (rolCostBdM[role]!=0) {
                    sessDestruct=ProtDestructCost(i,role,node.in[i].node_id,attack_position,attackerState);
                    if (sessDestruct != NU) { if (rolCostBdM[role] == NU) rolCostBdM[role]=sessDestruct; else if (sessDestruct < rolCostBdM[role]) rolCostBdM[role]=sessDestruct; }
           }

	 	}

        // min cost of mandatory roles compromissions and count of compromisable OK roles
        for(role : int[0,diMr-1] ) if ( node.RoleParams[role][0]!=rS and node.RoleParams[role][1]!=NU ) { //no system and no tranparent roles
            if ( node.RoleParams[role][1]==1 ) { // mandatory role  
                if (not rolOk[role] ) return 0; // peer Position  not available or in non F state
                if (rolCostBdM[role]!=NU) {
                    if ( (tcost==NU) or (rolCostBdM[role]<tcost) ) tcost=rolCostBdM[role]; // minimal cost of  the compromissions of the mandatory role => tcost 
                }            
            } else if (node.RoleParams[role][1]==0) if (rolOk[role]) nbOKnMand++;          
        }

        if ( nbOKnMand < node.actThreshold ) return 0; // not enough of non mandatory roles are active

        nbtocomp=1+nbOKnMand-node.actThreshold; // number of opeional role necessary to compromise

        // minimal cost of the non mandatory roles' compromission
        for(k : int[0,diMr-1] ) {
          int tr1=NU, j=NU;
          //choice of a role with the minimal cost 
          for(role : int[0,diMr-1] ) if ( (node.RoleParams[role][0]!=rS) and (node.RoleParams[role][1]==0) and (rolCostBdM[role] != NU) and (tr<nbtocomp) )  { //only non mandatory roles
            if ( (tr1==NU) or (tr1>rolCostBdM[role]) )  { tr1=rolCostBdM[role]; j=role; } // role of min cost
          }
          if (tr1!=NU) { tr++; bdCost = (bdCost!=NU)?bdCost:0 + tr1; rolCostBdM[j]=NU; }
        }     
        if (tr < nbtocomp) return tcost; // impossible to comproomise enough of no mandatory roles
        if (tcost==NU) return bdCost;    // it was impossible to compromise mandatory roles  
        return bdCost>tcost?tcost:bdCost; // choice between costs of mandatory or non mandatory role compromissions 
    }



	int NoProducerDisp(int[NU,nbNodes-1] node_id, bool fallback) {  // true if essential producers present on peer position or if necessary min of comm destruction by malwares!!!!
        int NoProducerDispCost, suppl=0;
        if (fallback and  not isFallBackActiv(node_id,sN) ) return NU;
        if ( (not fallback) and  isFallBackActiv(node_id,sN) ) suppl=node.AnomDetParam[sN-1];
        NoProducerDispCost=minNonDispCost();
        if (NoProducerDispCost == NU) return NU;
        NoProducerDispCost+=suppl;
        if ( (NoProducerDispCost+costs)<= maxCosts ) return NoProducerDispCost;
        return NU;
	}

    void updateNoProducerDisp(int[NU,nbNodes-1] node_id, bool fallback) {
        int suppl=0;
        int NoProducerDispCost=minNonDispCost();
        if ( (not fallback) and isFallBackActiv(node_id,sN) ) suppl=node.AnomDetParam[sN-1];
        costs += NoProducerDispCost+suppl;
        if (not fallback) nodeState[node_id].locat=sN;
    }


	int[NU,MaxUnitCost] MinCostMalware(int[NU,nbNodes-1] node_id,int[0,NbStates-1] target_state, bool fallback) {  // malware on input or bad data et peer (partner) position  
	    int cost=NU,tcost=NU, suppl=0;
        if ((node.node_type==cK) and (target_state==sB)) return NU;
        if (fallback and not isFallBackActiv(node_id,target_state) ) return NU;
        if ( (not fallback) and isFallBackActiv(node_id,target_state)) suppl=node.AnomDetParam[target_state-1];
	    if (NbInputs <=0) return NU;
	 	for(i : int[0,diM-1] ) if (reachable(i)) if ( (nodeState[node.in[i].node_id].locat==sM) or ( (nodeState[node.in[i].node_id].locat==sB) and (node.in[i].attack_position==peer) )) {
            int[0,diMr-1] role = node.in[i].roleId;
            int[NU,2] attack_position=node.in[i].attack_position;
            int[0,NbStates-1] attackerState=nodeState[node.in[i].node_id].locat; 
            tcost=ProtProtectCost(i,role,node.in[i].node_id,attack_position,attackerState);

            if (tcost>NU and node.RoleParams[role][2+target_state]>NU) tcost+=node.RoleParams[role][2+target_state]; else tcost=NU;  // 3 cost for full malware, 4 malware BD only, 5 malware N only

            if (tcost>NU) if ( (cost==NU) or (tcost<cost) ) cost =tcost; 
		}
        if (cost<=NU) return NU;
        cost+=suppl;
	    if ( (cost+costs)<= maxCosts )	return cost; else return NU;

	}


	void updateMalware(int[NU,nbNodes-1] node_id, int[0,NbStates-1] target_state, bool fallback) {
	    int[NU,MaxUnitCost] tmp=MinCostMalware(node_id,target_state, fallback);
	    if (tmp >0) costs=costs+tmp;
	    if (not fallback) nodeState[node_id].locat=target_state;
	}


	int[NU,MaxUnitCost] RemoteSecrCost(int[NU,nbNodes-1] node_id) {  // malware on inputs try to steal all locally stored secrets 
	    int cost=NU,tcost=NU,z=0;
	    if (NbInputs <=0) return NU;
	    for(i : int[0,nbVar-1] ) if ((!StolenSecrets[i]) and StoredSecrets[node.node_id][i] ) z++;
        if (z==0) return NU;
	 	for(i : int[0,diM-1] ) if (reachable(i)) if (nodeState[node.in[i].node_id].locat==sM) {
            int[0,diMr-1] role = node.in[i].roleId;
            int[NU,2] attack_position=node.in[i].attack_position;
            int[0,NbStates-1] attackerState=nodeState[node.in[i].node_id].locat; 
            tcost=ProtProtectCost(i,role,node.in[i].node_id,attack_position,attackerState); //protocol access cost
            if (tcost>NU and node.RoleParams[role][6]>NU) tcost+=node.RoleParams[role][6];else tcost=NU;
            if (tcost>NU) if ( (cost==NU) or (tcost<cost) ) cost=tcost; 
		}
        if (cost<=NU) return NU;
 	    if ( (cost+costs)<= maxCosts )	return cost; else return NU;

	}


	void setRemoteSecr(int[NU,nbNodes-1] node_id) {
	    int[NU,MaxUnitCost] tmp=RemoteSecrCost(node_id);
	    if (tmp >0) costs=costs+tmp;
        for(i : int[0,nbVar-1] ) if ((!StolenSecrets[i]) and StoredSecrets[node.node_id][i] ) StolenSecrets[i]=true;
	}


	int[NU,maxCosts] LocalVarCost(int[NU,nbNodes-1] node_id) {
	    int[NU,MaxUnitCost] cost;
	    for(i : int[0,nbVar-1] ) {
	        if ((!StolenSecrets[i]) and StoredSecrets[node.node_id][i] ) {
	            cost=node.secrTheftCost;
	            if ((cost+costs)<=maxCosts) return cost;
                return NU;
	        }
	    };
	    return NU;
	}

	void setLocalSecr(int[NU,nbNodes-1] node_id){
	    int[NU,MaxUnitCost] cost;
	    for(i : int[0,nbVar-1] ) if ((!StolenSecrets[i]) and StoredSecrets[node.node_id][i] ) StolenSecrets[i]=true; 
	    cost=node.secrTheftCost;
	    costs=costs+cost;
        return;
	}

    int MinFB(int[NU,nbNodes-1] node_id, bool fallback) {
        int mal=MinCostMalware(node_id,sB,fallback), bd=BadData(node_id,fallback);
        if (mal<0) return bd;
        if (bd<0) return mal;
        if (bd>mal) return mal;
        return bd;
    }
    void UpdateFB(int[NU,nbNodes-1] node_id, bool fallback) {
        int mal=MinCostMalware(node_id,sB,fallback), bd=BadData(node_id,fallback);
        if (mal<0) {updateBadData(node_id,fallback);return;};
        if (bd<0) {updateMalware(node_id,sB,fallback);return;};
        if (bd>mal) {updateMalware(node_id,sB,fallback);return;};
        updateBadData(node_id,fallback);return;
    }

    int MinFN(int[NU,nbNodes-1] node_id, bool fallback) {
        int mal=MinCostMalware(node_id,sN,fallback), noProd=NoProducerDisp(node_id,fallback);
        if (mal<0) return noProd;
        if (noProd<0) return mal;
        if (noProd>mal) return mal;
        return noProd;
    }
    void UpdateFN(int[NU,nbNodes-1] node_id, bool fallback) {
        int mal=MinCostMalware(node_id,sN,fallback), noProd=NoProducerDisp(node_id,fallback);
        if (mal<0) {updateNoProducerDisp(node_id,fallback);return;};
        if (noProd<0) {updateMalware(node_id,sN,fallback);return;};
        if (noProd>mal) {updateMalware(node_id,sN,fallback);return;};
        updateNoProducerDisp(node_id,fallback);return;
    }


    int MinFM(int[NU,nbNodes-1] node_id, bool fallback) {
        return MinCostMalware(node_id,sM,fallback);
    }
    void UpdateFM(int[NU,nbNodes-1] node_id, bool fallback) {
        updateMalware(node_id,sM,fallback);return;
    }

