// Place template instantiations here.

DmzHttp=DmzHttpt(0);DmzLinx=DmzLinxt(1);ExBrowser=ExBrowsert(2);ExtHack=ExtHackt(3);ExtWind=ExtWindt(4);FW=FWt(5);InBrowser=InBrowsert(6);IntHack=IntHackt(7);IntWind=IntWindt(8);Internet=Internett(9);Intranet=Intranett(10);IoTLinx1=IoTLinx1t(11);IoTLinx2=IoTLinx2t(12);IoTSrv1=IoTSrv1t(13);IoTSrv2=IoTSrv2t(14); // all processeses
Go=Start();

// List one or more processes to be composed into a system.
system   DmzHttp,DmzLinx,ExBrowser,ExtHack,ExtWind,FW,InBrowser,IntHack,IntWind,Internet,Intranet,IoTLinx1,IoTLinx2,IoTSrv1,IoTSrv2<Go;  // the Go process has a higher priority
